// Parse Phase 1 Instructions
const directorResponse = $json;
const completeContext = $('Initialize Complete Workflow').first().json.completeWorkflowContext;

const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid Phase 1 instructions received",
    error: true,
    task_id: "phase1_error"
  }];
}

const instruction = instructionData.instruction;
let instructionText = '';

instructionText += `# PHASE 1: IDEA CATEGORIZATION (Part of Complete Workflow)\n\n`;
instructionText += `## COMPLETE WORKFLOW CONTEXT\n`;
instructionText += `- Session ID: ${completeContext.sessionId}\n`;
instructionText += `- Total Workflow: Phase 1 (Categorization) → Phase 2 (Database Creation)\n`;
instructionText += `- Current Phase: ${completeContext.currentPhase} → phase1_categorization\n\n`;

instructionText += `## PHASE 1 OBJECTIVE\n`;
instructionText += `Retrieve ideas from the source database and categorize them for database routing.\n`;
instructionText += `Each idea will be analyzed and assigned to: projects, knowledge, or journal databases.\n\n`;

if (instruction.parameters) {
  instructionText += `## TASK PARAMETERS\n`;
  Object.entries(instruction.parameters).forEach(([key, value]) => {
    instructionText += `- ${key}: ${value}\n`;
  });
  instructionText += '\n';
}

if (instructionData.categorization_methodology) {
  instructionText += `## CATEGORIZATION METHODOLOGY\n`;

  if (instructionData.categorization_methodology.multi_idea_parsing_rules) {
    instructionText += `### MULTI-IDEA PARSING:\n`;
    instructionData.categorization_methodology.multi_idea_parsing_rules.forEach(rule => {
      instructionText += `- ${rule}\n`;
    });
    instructionText += '\n';
  }

  if (instructionData.categorization_methodology.database_routing_criteria) {
    instructionText += `### DATABASE ROUTING CRITERIA:\n`;
    Object.entries(instructionData.categorization_methodology.database_routing_criteria).forEach(([key, criteria]) => {
      instructionText += `**${key.toUpperCase()}:**\n`;
      if (criteria.description) instructionText += `- ${criteria.description}\n`;
      if (criteria.keywords) instructionText += `- Keywords: ${criteria.keywords.join(', ')}\n`;
      instructionText += '\n';
    });
  }
}

instructionText += `## EXECUTION STEPS\n`;
instructionText += `1. Use get_ideas tool to retrieve ${instruction.parameters?.limit || 3} ideas with status='Not Started'\n`;
instructionText += `2. Analyze each idea's content to identify distinct concepts/projects\n`;
instructionText += `3. Apply categorization methodology to assign database routes\n`;
instructionText += `4. Update source ideas to 'Done' status\n`;
instructionText += `5. Return categorized results for Phase 2 database creation\n\n`;

instructionText += `## EXPECTED OUTPUT FOR PHASE 2\n`;
instructionText += `Return results with categorized_ideas array containing:\n`;
instructionText += `{\n`;
instructionText += `  "agent_id": "notion",\n`;
instructionText += `  "task_id": "${instructionData.task_id}",\n`;
instructionText += `  "phase": "categorization_complete",\n`;
instructionText += `  "results": {\n`;
instructionText += `    "ideas_processed": [\n`;
instructionText += `      {\n`;
instructionText += `        "idea_id": "source_id",\n`;
instructionText += `        "title": "extracted_title",\n`;
instructionText += `        "original_content": "full_content",\n`;
instructionText += `        "categorization": {\n`;
instructionText += `          "database": "projects|knowledge|journal",\n`;
instructionText += `          "database_id": "${completeContext.phase2Config.target_databases.projects || 'target_db_id'}",\n`;
instructionText += `          "category": "specific_category",\n`;
instructionText += `          "priority": "High|Medium|Low",\n`;
instructionText += `          "tags": ["array", "of", "tags"]\n`;
instructionText += `        }\n`;
instructionText += `      }\n`;
instructionText += `    ]\n`;
instructionText += `  },\n`;
instructionText += `  "status": {\n`;
instructionText += `    "success": true,\n`;
instructionText += `    "next_phase": "database_creation_required"\n`;
instructionText += `  }\n`;
instructionText += `}\n\n`;

instructionText += `**This is Phase 1 of a 2-phase workflow. Your results will feed directly into Phase 2 for database creation.**\n\n`;
instructionText += `**BEGIN PHASE 1 CATEGORIZATION NOW**\n`;

return [{
  instructionText,
  task_id: instructionData.task_id,
  phase: 'phase1_categorization',
  completeContext,
  directorResponse: instructionData
}];

